interface CompileContext {
  node: { id: string; type: string; data: Record<string, unknown> };
  inputs: Map<string, string>;
  outputVar: string;
  sanitizedId: string;
  escapeString: (str: string) => string;
}

export function compile(ctx: CompileContext): string {
  const textInput = ctx.inputs.get('text') || 'null';
  const format = ctx.node.data?.format || 'uppercase';
  const prefix = ctx.node.data?.prefix || '';
  const suffix = ctx.node.data?.suffix || '';
  const trim = ctx.node.data?.trim === true;

  return `
  // --- TS Text Formatter: ${ctx.node.id} ---
  let ${ctx.outputVar}_result = null;
  let ${ctx.outputVar}_length = 0;
  (function() {
    const text = ${textInput};
    if (text !== null && text !== undefined) {
      let strText = String(text);
      const shouldTrim = ${trim};
      if (shouldTrim) {
        strText = strText.trim();
      }
      const format = "${format}";
      let formatted = strText;
      if (format === 'uppercase') {
        formatted = strText.toUpperCase();
      } else if (format === 'lowercase') {
        formatted = strText.toLowerCase();
      } else if (format === 'titlecase') {
        const words = strText.split(' ');
        let titleResult = '';
        for (const word of words) {
          if (word.length > 0) {
            if (titleResult.length > 0) {
              titleResult = titleResult + ' ';
            }
            titleResult = titleResult + word.charAt(0).toUpperCase() + word.slice(1).toLowerCase();
          }
        }
        formatted = titleResult;
      } else if (format === 'reverse') {
        formatted = strText.split('').reverse().join('');
      }
      ${ctx.outputVar}_result = "${prefix}" + formatted + "${suffix}";
      ${ctx.outputVar}_length = ${ctx.outputVar}_result.length;
    }
  })();
  workflow_context["${ctx.node.id}"] = ${ctx.outputVar}_result;
  workflow_context["${ctx.node.id}_length"] = ${ctx.outputVar}_length;
`;
}

