export async function execute(inputs: Record<string, unknown>): Promise<{ result: string; length: number }> {
  let text = String(inputs.text || '');
  const format = String(inputs.format || 'uppercase');
  const prefix = String(inputs.prefix || '');
  const suffix = String(inputs.suffix || '');
  const trim = inputs.trim === true;

  if (trim) {
    text = text.trim();
  }

  let result: string;
  switch (format) {
    case 'uppercase':
      result = text.toUpperCase();
      break;
    case 'lowercase':
      result = text.toLowerCase();
      break;
    case 'titlecase':
      result = text.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(' ');
      break;
    case 'reverse':
      result = text.split('').reverse().join('');
      break;
    default:
      result = text;
  }

  result = prefix + result + suffix;
  return { result, length: result.length };
}

