export function compile(ctx: CompileContext): string {
  const jsonInput = ctx.inputs.get('json') || 'null';
  const path = ctx.node.data?.path || '';
  const defaultValue = ctx.node.data?.defaultValue || '';
  const stringify = ctx.node.data?.stringify === true;

  return `
  // --- TS JSON Parser: ${ctx.node.id} ---
  let ${ctx.outputVar}_value = null;
  let ${ctx.outputVar}_parsed = null;
  let ${ctx.outputVar}_valid = false;
  (function() {
    const jsonStr = ${jsonInput};
    const jsonPath = "${path}";
    const defaultVal = "${defaultValue}";
    const shouldStringify = ${stringify};
    try {
      const parsedObj = JSON.parse(jsonStr);
      ${ctx.outputVar}_parsed = parsedObj;
      ${ctx.outputVar}_valid = true;

      if (jsonPath && jsonPath.length > 0) {
        const parts = jsonPath.split('.');
        let current = parsedObj;
        for (const part of parts) {
          if (current !== null && current !== undefined && typeof current === 'object' && current[part] !== undefined) {
            current = current[part];
          } else {
            current = null;
            break;
          }
        }
        ${ctx.outputVar}_value = current !== null ? current : (defaultVal || null);
      } else {
        ${ctx.outputVar}_value = parsedObj;
      }
      if (shouldStringify && ${ctx.outputVar}_value !== null) {
        ${ctx.outputVar}_value = JSON.stringify(${ctx.outputVar}_value);
      }
    } catch (e) {
      ${ctx.outputVar}_valid = false;
      ${ctx.outputVar}_value = defaultVal || null;
    }
  })();
  workflow_context["${ctx.node.id}"] = ${ctx.outputVar}_value;
  workflow_context["${ctx.node.id}_parsed"] = ${ctx.outputVar}_parsed;
  workflow_context["${ctx.node.id}_valid"] = ${ctx.outputVar}_valid;
`;
}

