export async function execute(inputs: Record<string, unknown>): Promise<{ value: unknown; parsed: unknown; valid: boolean }> {
  const jsonStr = String(inputs.json || '');
  const path = String(inputs.path || '');
  const defaultValue = inputs.defaultValue !== undefined ? inputs.defaultValue : null;
  const stringify = inputs.stringify === true;

  try {
    const parsed = JSON.parse(jsonStr);
    let value: unknown = parsed;

    if (path) {
      const parts = path.split('.');
      for (const part of parts) {
        if (value && typeof value === 'object' && (value as Record<string, unknown>)[part] !== undefined) {
          value = (value as Record<string, unknown>)[part];
        } else {
          value = null;
          break;
        }
      }
    }

    if (value === null && defaultValue !== null) {
      value = defaultValue;
    }

    if (stringify && value !== null) {
      value = JSON.stringify(value);
    }

    return { value, parsed, valid: true };
  } catch {
    return { value: defaultValue, parsed: null, valid: false };
  }
}

