interface RuntimeContext {
  log: (level: string, message: string) => void;
  nodeId: string;
  nodeData: Record<string, unknown>;
}

export function preExecute(inputs: Record<string, unknown>, ctx: RuntimeContext): Record<string, unknown> {
  if (inputs.custom_endpoint) {
    ctx.log('info', `[CustomAI] Using custom endpoint: ${inputs.custom_endpoint}`);
    return {
      ...inputs,
      _useCustomProvider: true,
      _customEndpoint: inputs.custom_endpoint
    };
  }
  return inputs;
}

export function postExecute(result: unknown, inputs: Record<string, unknown>, ctx: RuntimeContext): unknown {
  if (inputs._useCustomProvider) {
    ctx.log('info', '[CustomAI] Response from custom provider processed');
  }
  return result;
}
